import pytest

def test_open_savings_account_one_cent_below_minimum(verified_customer_client):
    payload = {
        "customer_id": verified_customer_client["customer_id"],
        "initial_deposit": 99.99,
        "currency": "USD"
    }
    resp = verified_customer_client["session"].post(
        "/accounts/savings", json=payload
    )
    assert resp.status_code == 422, f"Expected 422, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert "account_id" not in body

import pytest

def test_open_savings_account_unverified_customer_rejected(unverified_customer_client):
    payload = {
        "customer_id": unverified_customer_client["customer_id"],
        "initial_deposit": 200.00,
        "currency": "USD"
    }
    resp = unverified_customer_client["session"].post(
        "/accounts/savings", json=payload
    )
    assert resp.status_code in (403, 422), (
        f"Expected 403 or 422 for unverified customer, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert "account_id" not in body
